public void testGetLInfNormAllZeros() {
    double[] vec_zeros = {0.0, 0.0, 0.0};
    ArrayRealVector v_zeros = new ArrayRealVector(vec_zeros);
    double d_getLInfNorm = v_zeros.getLInfNorm();
    assertEquals("LInfNorm of zero vector should be 0", 0.0, d_getLInfNorm);
}

public void testGetLInfNormSingleElement() {
    double[] vec_single = {-9.0};
    ArrayRealVector v_single = new ArrayRealVector(vec_single);
    double d_getLInfNorm = v_single.getLInfNorm();
    assertEquals("LInfNorm of single negative element", 9.0, d_getLInfNorm);
}

public void testGetLInfNormAllPositive() {
    double[] vec_positive = {1.5, 2.0, 0.5};
    ArrayRealVector v_positive = new ArrayRealVector(vec_positive);
    double d_getLInfNorm = v_positive.getLInfNorm();
    assertEquals("LInfNorm of all positive values", 2.0, d_getLInfNorm);
}

public void testGetLInfNormSparse() {
    double[] vec_sparse = {0.0, 0.0, 7.5, 0.0, -3.2, 0.0};
    OpenMapRealVector v_sparse = new OpenMapRealVector(vec_sparse);
    double d_getLInfNorm = v_sparse.getLInfNorm();
    assertEquals("LInfNorm of sparse vector", 7.5, d_getLInfNorm);
}

public void testGetLInfNormAllZerosSparse() {
    double[] vec_zeros = {0.0, 0.0, 0.0, 0.0};
    OpenMapRealVector v_zeros = new OpenMapRealVector(vec_zeros);
    double d_getLInfNorm = v_zeros.getLInfNorm();
    assertEquals("LInfNorm of zero sparse vector", 0.0, d_getLInfNorm);
}
